    <script>document.querySelectorAll('[data-purchase-notifications]').forEach(function(root){var items=Array.from(root.querySelectorAll('[data-purchase-notification]')),index=0,interval=Math.max(5000,Number(root.dataset.interval)||12000),duration=Math.max(2000,Number(root.dataset.duration)||6000),delay=Math.max(0,Number(root.dataset.delay)||4000);if(!items.length)return;var show=function(){var item=items[index%items.length];items.forEach(function(node){node.classList.remove('is-visible');node.hidden=true});item.hidden=false;requestAnimationFrame(function(){requestAnimationFrame(function(){item.classList.add('is-visible')})});setTimeout(function(){item.classList.remove('is-visible');setTimeout(function(){item.hidden=true},450)},Math.min(duration,interval-700));index++;setTimeout(show,interval)};setTimeout(show,delay)});</script>
