<script>
document.querySelectorAll('.signal-close').forEach(function(button){button.addEventListener('click',function(){var signal=button.closest('.live-signal');if(signal)signal.remove()})});
document.querySelectorAll('[data-media-slider]').forEach(function(root){var slides=Array.from(root.querySelectorAll('.media-slide')),dots=Array.from(root.querySelectorAll('.media-slider-dot')),track=root.querySelector('.media-slider-track'),index=0,timer=null,fade=root.dataset.style==='fade',loop=root.dataset.loop==='1';if(slides.length<2)return;var go=function(next){if(loop)next=(next+slides.length)%slides.length;else next=Math.max(0,Math.min(slides.length-1,next));index=next;slides.forEach(function(s,i){s.classList.toggle('is-active',i===index)});dots.forEach(function(d,i){d.classList.toggle('is-active',i===index)});if(!fade)track.scrollTo({left:slides[index].offsetLeft,behavior:'smooth'})};var play=function(){if(root.dataset.autoplay==='1'){clearInterval(timer);timer=setInterval(function(){go(index+1)},Math.max(1500,Number(root.dataset.interval)||4000))}};root.querySelector('.slider-arrow-prev')?.addEventListener('click',function(){go(index-1);play()});root.querySelector('.slider-arrow-next')?.addEventListener('click',function(){go(index+1);play()});dots.forEach(function(dot){dot.addEventListener('click',function(){go(Number(dot.dataset.slide));play()})});if(root.dataset.pauseHover==='1'){root.addEventListener('mouseenter',function(){clearInterval(timer)});root.addEventListener('mouseleave',play)}play()});
document.querySelectorAll('[data-accordion]').forEach(function(root){if(root.dataset.multiple==='1')return;root.querySelectorAll('details').forEach(function(item){item.addEventListener('toggle',function(){if(!item.open)return;root.querySelectorAll('details[open]').forEach(function(other){if(other!==item)other.open=false})})})});
document.querySelectorAll('[data-viewer-counter]').forEach(function(root){var label=root.querySelector('[data-viewer-label]'),template=root.dataset.template||'{count}',refresh=function(){fetch(root.dataset.url,{headers:{Accept:'application/json'}}).then(function(r){return r.ok?r.json():Promise.reject()}).then(function(data){label.textContent=template.replace('{count}',String(data.count||0))}).catch(function(){})};setInterval(refresh,Math.max(10,Number(root.dataset.poll)||30)*1000)});
</script>
<script>document.querySelectorAll('[data-countdown]').forEach(function(el){var end=new Date(el.dataset.countdown).getTime();var tick=function(){var diff=Math.max(0,end-Date.now()),values={days:Math.floor(diff/86400000),hours:Math.floor(diff%86400000/3600000),minutes:Math.floor(diff%3600000/60000),seconds:Math.floor(diff%60000/1000)};Object.keys(values).forEach(function(unit){var node=el.querySelector('[data-unit="'+unit+'"]');if(node)node.textContent=String(values[unit]).padStart(2,'0')})};tick();setInterval(tick,1000)});</script>@if($showOrderForm)<script>var fieldConditions=@json($formFields->mapWithKeys(fn($field)=>[$field['internal_name']??$field['key']=>($field['conditions']??[])])->all());var readField=function(key){var nodes=document.querySelectorAll('[name="custom['+key+']"], [name="custom['+key+'][]"]'),checked=Array.from(nodes).filter(function(n){return n.checked}).map(function(n){return n.value});var node=nodes[0];return checked.length?checked:(node?node.value:'')};var updateFields=function(){Object.keys(fieldConditions).forEach(function(key){var conditions=fieldConditions[key]||[],visible=conditions.every(function(c){var actual=readField(c.field),expected=String(c.value||'');return c.operator==='not_equals'?String(actual)!==expected:c.operator==='contains'?(Array.isArray(actual)?actual.indexOf(expected)>=0:String(actual).indexOf(expected)>=0):String(actual)===expected});var wrapper=document.querySelector('[data-form-field="'+key+'"]');if(wrapper)wrapper.style.display=visible?'':'none'});};document.querySelectorAll('input[name^="custom["],select[name^="custom["],textarea[name^="custom["]').forEach(function(n){n.addEventListener('change',updateFields);n.addEventListener('input',updateFields)});updateFields();</script>@endif</body></html>
